// Fetch marketplace connections whose tokens expire within 1 hour.
// Uses shop_marketplace_connections_decrypted view to get plaintext tokens.
// Filters: is_active=true AND token_expires_at < now() + 1 hour.

const Sentry = require('@sentry/node');
// @inline env-supabase-preamble
const https = require('https');

const SUPABASE_URL = $env.SUPABASE_URL;
if (!SUPABASE_URL) throw new Error('SUPABASE_URL environment variable not configured');
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
// @end-inline env-supabase-preamble

// Timestamp: now + 1 hour (ISO 8601)
const expiryThreshold = new Date(Date.now() + 60 * 60 * 1000).toISOString();

// @inline supabase-request
async function supabaseRequest(path, method, body, opts) {
  const url = `${SUPABASE_URL}/rest/v1/${path}`;
  return new Promise((resolve, reject) => {
    const match = url.match(/^https?:\/\/([^/]+)(\/.*)$/);
    if (!match) { reject(new Error('Invalid SUPABASE_URL')); return; }
    const prefer = (opts && opts.prefer) || 'return=representation';
    const options = {
      hostname: match[1],
      path: match[2],
      method: method || 'GET',
      headers: {
        'apikey': SUPABASE_KEY,
        'Authorization': `Bearer ${SUPABASE_KEY}`,
        'Content-Type': 'application/json',
        'Prefer': prefer,
      },
    };
    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        if (res.statusCode >= 400) {
          reject(new Error(`Supabase ${method || 'GET'} ${path} ${res.statusCode}: ${data}`));
          return;
        }
        try {
          resolve(data ? JSON.parse(data) : null);
        } catch (e) {
          reject(new Error(`Parse error for ${path}: ${data}`));
        }
      });
    });
    req.on('error', reject);
    if (body !== undefined && body !== null) req.write(JSON.stringify(body));
    req.end();
  });
}
// @end-inline supabase-request

// @inline supabase-crud
async function supabaseGet(table, filterOrParams, value, select) {
  let qs;
  if (typeof filterOrParams === 'string') {
    const p = new URLSearchParams();
    p.append(filterOrParams, `eq.${value}`);
    if (select) p.append('select', select);
    p.append('limit', '1');
    qs = p.toString();
  } else {
    qs = new URLSearchParams(filterOrParams).toString();
  }
  return supabaseRequest(`${table}?${qs}`, 'GET');
}

async function supabasePatch(path, body, opts) {
  return supabaseRequest(path, 'PATCH', body, opts);
}
// @end-inline supabase-crud

try {
  // Use decrypted view to get plaintext tokens for refresh
  const connections = await supabaseGet('shop_marketplace_connections_decrypted', {
    select: 'id,marketplace,account_id,access_token,refresh_token,token_expires_at',
    is_active: 'eq.true',
    token_expires_at: `lt.${expiryThreshold}`,
  });

  if (!Array.isArray(connections)) {
    throw new Error(`Unexpected response: ${JSON.stringify(connections)}`);
  }

  Sentry.addBreadcrumb({
    message: `Token refresh: found ${connections.length} expiring connection(s)`,
    level: 'info',
  });

  if (connections.length === 0) {
    return [];
  }

  // Return one item per connection for SplitInBatches
  return connections.map((conn) => ({
    connection_id: conn.id,
    marketplace: conn.marketplace,
    account_id: conn.account_id || null,
    access_token: conn.access_token,
    refresh_token: conn.refresh_token || null,
    token_expires_at: conn.token_expires_at,
  }));
} catch (err) {
  Sentry.captureException(err);
  await Sentry.flush(2000);
  throw err;
}

// OLX token refresh.
// OLX token endpoint: https://www.olx.pl/api/open/oauth/token
// Credentials sent in POST body (not Basic auth).
// Sandbox: OLX_USE_SANDBOX=true → https://www-sandbox.olx.pl/api/open/oauth/token

const Sentry = require('@sentry/node');
const https = require('https');

const input = $input.first().json;

const isSandbox = $env.OLX_USE_SANDBOX === 'true';
const OLX_TOKEN_URL = isSandbox
  ? 'https://www-sandbox.olx.pl/api/open/oauth/token'
  : 'https://www.olx.pl/api/open/oauth/token';

if (!input.refresh_token) {
  throw new Error(`OLX connection ${input.connection_id} has no refresh token — cannot refresh`);
}

const body = new URLSearchParams({
  grant_type: 'refresh_token',
  client_id: $env.OLX_CLIENT_ID,
  client_secret: $env.OLX_CLIENT_SECRET,
  refresh_token: input.refresh_token,
}).toString();

async function postFormUrl(url, body) {
  return new Promise((resolve, reject) => {
    const options = {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
        'Content-Length': Buffer.byteLength(body),
      },
    };
    const req = https.request(url, options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        try {
          resolve({ status: res.statusCode, body: JSON.parse(data) });
        } catch (e) {
          resolve({ status: res.statusCode, body: data });
        }
      });
    });
    req.on('error', reject);
    req.write(body);
    req.end();
  });
}

try {
  const result = await postFormUrl(OLX_TOKEN_URL, body);

  if (result.status >= 400 || !result.body.access_token) {
    throw new Error(`OLX token refresh failed: HTTP ${result.status} — ${JSON.stringify(result.body)}`);
  }

  const expiresAt = new Date(
    Date.now() + (result.body.expires_in || 3600) * 1000
  ).toISOString();

  Sentry.addBreadcrumb({
    message: `OLX token refreshed for connection ${input.connection_id}`,
    level: 'info',
  });

  return {
    connection_id: input.connection_id,
    marketplace: 'olx',
    new_access_token: result.body.access_token,
    new_refresh_token: result.body.refresh_token || input.refresh_token,
    new_expires_at: expiresAt,
  };
} catch (err) {
  Sentry.captureException(err);
  await Sentry.flush(2000);
  return {
    connection_id: input.connection_id,
    marketplace: 'olx',
    refresh_error: err.message,
  };
}

// Allegro token refresh.
// Allegro token endpoint: https://allegro.pl/auth/oauth/token
// Uses Basic auth (base64 client_id:client_secret).
// Sandbox: ALLEGRO_USE_SANDBOX=true → https://allegro.pl.allegrosandbox.pl/auth/oauth/token

const Sentry = require('@sentry/node');
const https = require('https');

const input = $input.first().json;

const isSandbox = $env.ALLEGRO_USE_SANDBOX === 'true';
const ALLEGRO_TOKEN_URL = isSandbox
  ? 'https://allegro.pl.allegrosandbox.pl/auth/oauth/token'
  : 'https://allegro.pl/auth/oauth/token';

if (!input.refresh_token) {
  throw new Error(`Allegro connection ${input.connection_id} has no refresh token — cannot refresh`);
}

const body = new URLSearchParams({
  grant_type: 'refresh_token',
  refresh_token: input.refresh_token,
}).toString();

// Allegro uses Basic auth: base64(client_id:client_secret)
const basicAuth = Buffer.from(
  `${$env.ALLEGRO_CLIENT_ID}:${$env.ALLEGRO_CLIENT_SECRET}`
).toString('base64');

async function postFormUrl(url, body, authHeader) {
  return new Promise((resolve, reject) => {
    const options = {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
        'Content-Length': Buffer.byteLength(body),
        'Authorization': authHeader,
      },
    };
    const req = https.request(url, options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        try {
          resolve({ status: res.statusCode, body: JSON.parse(data) });
        } catch (e) {
          resolve({ status: res.statusCode, body: data });
        }
      });
    });
    req.on('error', reject);
    req.write(body);
    req.end();
  });
}

try {
  const result = await postFormUrl(ALLEGRO_TOKEN_URL, body, `Basic ${basicAuth}`);

  if (result.status >= 400 || !result.body.access_token) {
    throw new Error(`Allegro token refresh failed: HTTP ${result.status} — ${JSON.stringify(result.body)}`);
  }

  const expiresAt = new Date(
    Date.now() + (result.body.expires_in || 43200) * 1000
  ).toISOString();

  Sentry.addBreadcrumb({
    message: `Allegro token refreshed for connection ${input.connection_id}`,
    level: 'info',
  });

  return {
    connection_id: input.connection_id,
    marketplace: 'allegro',
    new_access_token: result.body.access_token,
    new_refresh_token: result.body.refresh_token || input.refresh_token,
    new_expires_at: expiresAt,
  };
} catch (err) {
  Sentry.captureException(err);
  await Sentry.flush(2000);
  return {
    connection_id: input.connection_id,
    marketplace: 'allegro',
    refresh_error: err.message,
  };
}

// Unsupported marketplace — log and skip.
const Sentry = require('@sentry/node');
const input = $input.first().json;
const msg = `Token refresh skipped: unsupported marketplace '${input.marketplace}' for connection ${input.connection_id}`;
Sentry.captureException(new Error(msg));
await Sentry.flush(2000);
return { connection_id: input.connection_id, marketplace: input.marketplace, refresh_error: msg };

// Merge refresh results from OLX and Allegro branches.
// Passes through whichever branch produced output.
const branches = ['OLX Refresh Token', 'Allegro Refresh Token', 'Unsupported Marketplace'];
let result = null;
for (const branch of branches) {
  try {
    const items = $(branch).all();
    if (items.length > 0) { result = items[0].json; break; }
  } catch (e) { /* branch not executed */ }
}
if (!result) throw new Error('No marketplace refresh branch produced output');
return result;

// Persist refreshed tokens via update_marketplace_tokens RPC.
// The SECURITY DEFINER RPC handles pgcrypto encryption (pgp_sym_encrypt).
// On refresh failure, mark connection as is_active=false to prevent retry loops.

const Sentry = require('@sentry/node');
// @inline env-supabase-preamble
const https = require('https');

const SUPABASE_URL = $env.SUPABASE_URL;
if (!SUPABASE_URL) throw new Error('SUPABASE_URL environment variable not configured');
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
// @end-inline env-supabase-preamble

const input = $input.first().json;

// @inline supabase-request
async function supabaseRequest(path, method, body, opts) {
  const url = `${SUPABASE_URL}/rest/v1/${path}`;
  return new Promise((resolve, reject) => {
    const match = url.match(/^https?:\/\/([^/]+)(\/.*)$/);
    if (!match) { reject(new Error('Invalid SUPABASE_URL')); return; }
    const prefer = (opts && opts.prefer) || 'return=representation';
    const options = {
      hostname: match[1],
      path: match[2],
      method: method || 'GET',
      headers: {
        'apikey': SUPABASE_KEY,
        'Authorization': `Bearer ${SUPABASE_KEY}`,
        'Content-Type': 'application/json',
        'Prefer': prefer,
      },
    };
    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        if (res.statusCode >= 400) {
          reject(new Error(`Supabase ${method || 'GET'} ${path} ${res.statusCode}: ${data}`));
          return;
        }
        try {
          resolve(data ? JSON.parse(data) : null);
        } catch (e) {
          reject(new Error(`Parse error for ${path}: ${data}`));
        }
      });
    });
    req.on('error', reject);
    if (body !== undefined && body !== null) req.write(JSON.stringify(body));
    req.end();
  });
}
// @end-inline supabase-request

try {
  if (input.refresh_error) {
    // Refresh failed — deactivate connection to prevent retry loops
    Sentry.captureException(new Error(`[Token Refresh] Failed for ${input.marketplace} connection ${input.connection_id}: ${input.refresh_error}`));

    await supabaseRequest(
      `shop_marketplace_connections?id=eq.${input.connection_id}`,
      'PATCH',
      { is_active: false }
    );

    await Sentry.flush(2000);
    return {
      connection_id: input.connection_id,
      marketplace: input.marketplace,
      result: 'deactivated',
      reason: input.refresh_error,
    };
  }

  // Call update_marketplace_tokens RPC (handles encryption internally)
  await supabaseRequest(
    'rpc/update_marketplace_tokens',
    'POST',
    {
      p_connection_id: input.connection_id,
      p_access_token: input.new_access_token,
      p_refresh_token: input.new_refresh_token,
      p_token_expires_at: input.new_expires_at,
    }
  );

  Sentry.addBreadcrumb({
    message: `Tokens persisted for ${input.marketplace} connection ${input.connection_id}`,
    level: 'info',
  });

  return {
    connection_id: input.connection_id,
    marketplace: input.marketplace,
    result: 'refreshed',
    new_expires_at: input.new_expires_at,
  };
} catch (err) {
  Sentry.captureException(err);
  await Sentry.flush(2000);
  throw err;
}
